import psycopg2
from psycopg2 import sql, extras
from flask import Flask, request, jsonify
from functools import wraps
import re
from typing import List, Dict, Any, Optional

app = Flask(__name__)

DB_CONFIG = {
    'host': 'localhost',
    'database': 'analytics_db',
    'user': 'db_user',
    'password': 'db_password',
    'port': 5432
}

ALLOWED_TABLES = {
    'users', 'orders', 'products', 'transactions', 'analytics_events'
}

ALLOWED_COLUMNS = {
    'users': {'id', 'username', 'email', 'created_at', 'status'},
    'orders': {'id', 'user_id', 'total', 'status', 'created_at', 'updated_at'},
    'products': {'id', 'name', 'price', 'category', 'stock'},
    'transactions': {'id', 'order_id', 'amount', 'payment_method', 'timestamp'},
    'analytics_events': {'id', 'event_type', 'user_id', 'metadata', 'timestamp'}
}

ALLOWED_OPERATORS = {
    'eq': '=',
    'ne': '!=',
    'gt': '>',
    'gte': '>=',
    'lt': '<',
    'lte': '<=',
    'like': 'LIKE',
    'ilike': 'ILIKE',
    'in': 'IN',
    'not_in': 'NOT IN',
    'is_null': 'IS NULL',
    'is_not_null': 'IS NOT NULL'
}


def get_db_connection():
    return psycopg2.connect(**DB_CONFIG)


def validate_identifier(identifier: str, allowed_set: set) -> bool:
    if identifier not in allowed_set:
        return False
    if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', identifier):
        return False
    return True


def validate_table(table_name: str) -> bool:
    return validate_identifier(table_name, ALLOWED_TABLES)


def validate_columns(table_name: str, columns: List[str]) -> bool:
    if table_name not in ALLOWED_COLUMNS:
        return False
    allowed = ALLOWED_COLUMNS[table_name]
    return all(validate_identifier(col, allowed) for col in columns)


def validate_operator(operator: str) -> bool:
    return operator in ALLOWED_OPERATORS


def build_where_clause(table_name: str, filters: List[Dict[str, Any]]):
    if not filters:
        return sql.SQL(""), []
    
    conditions = []
    params = []
    
    for filter_item in filters:
        column = filter_item.get('column')
        operator = filter_item.get('operator', 'eq')
        value = filter_item.get('value')
        
        if not validate_identifier(column, ALLOWED_COLUMNS.get(table_name, set())):
            raise ValueError(f"Invalid column: {column}")
        
        if not validate_operator(operator):
            raise ValueError(f"Invalid operator: {operator}")
        
        sql_operator = ALLOWED_OPERATORS[operator]
        
        if operator in ['is_null', 'is_not_null']:
            conditions.append(
                sql.SQL("{} {}").format(
                    sql.Identifier(column),
                    sql.SQL(sql_operator)
                )
            )
        elif operator in ['in', 'not_in']:
            if not isinstance(value, list):
                raise ValueError(f"Value for {operator} must be a list")
            placeholders = sql.SQL(', ').join([sql.Placeholder()] * len(value))
            conditions.append(
                sql.SQL("{} {} ({})").format(
                    sql.Identifier(column),
                    sql.SQL(sql_operator),
                    placeholders
                )
            )
            params.extend(value)
        else:
            conditions.append(
                sql.SQL("{} {} {}").format(
                    sql.Identifier(column),
                    sql.SQL(sql_operator),
                    sql.Placeholder()
                )
            )
            params.append(value)
    
    where_clause = sql.SQL(" WHERE ") + sql.SQL(" AND ").join(conditions)
    return where_clause, params


def build_order_clause(table_name: str, order_by: Optional[List[Dict[str, str]]]):
    if not order_by:
        return sql.SQL("")
    
    order_parts = []
    for order_item in order_by:
        column = order_item.get('column')
        direction = order_item.get('direction', 'ASC').upper()
        
        if not validate_identifier(column, ALLOWED_COLUMNS.get(table_name, set())):
            raise ValueError(f"Invalid column for ordering: {column}")
        
        if direction not in ['ASC', 'DESC']:
            raise ValueError(f"Invalid order direction: {direction}")
        
        order_parts.append(
            sql.SQL("{} {}").format(
                sql.Identifier(column),
                sql.SQL(direction)
            )
        )
    
    return sql.SQL(" ORDER BY ") + sql.SQL(", ").join(order_parts)


@app.route('/api/query', methods=['POST'])
def query_data():
    try:
        data = request.get_json()
        
        table_name = data.get('table')
        columns = data.get('columns', ['*'])
        filters = data.get('filters', [])
        order_by = data.get('order_by', [])
        limit = data.get('limit', 100)
        offset = data.get('offset', 0)
        
        if not table_name:
            return jsonify({'error': 'Table name is required'}), 400
        
        if not validate_table(table_name):
            return jsonify({'error': 'Invalid or unauthorized table name'}), 400
        
        if columns != ['*'] and not validate_columns(table_name, columns):
            return jsonify({'error': 'Invalid or unauthorized column names'}), 400
        
        if not isinstance(limit, int) or limit < 1 or limit > 1000:
            return jsonify({'error': 'Limit must be between 1 and 1000'}), 400
        
        if not isinstance(offset, int) or offset < 0:
            return jsonify({'error': 'Offset must be non-negative'}), 400
        
        if columns == ['*']:
            select_clause = sql.SQL("SELECT *")
        else:
            select_clause = sql.SQL("SELECT {}").format(
                sql.SQL(', ').join(map(sql.Identifier, columns))
            )
        
        from_clause = sql.SQL(" FROM {}").format(sql.Identifier(table_name))
        
        where_clause, where_params = build_where_clause(table_name, filters)
        
        order_clause = build_order_clause(table_name, order_by)
        
        limit_clause = sql.SQL(" LIMIT {} OFFSET {}").format(
            sql.Placeholder(),
            sql.Placeholder()
        )
        
        query = select_clause + from_clause + where_clause + order_clause + limit_clause
        params = where_params + [limit, offset]
        
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=extras.RealDictCursor)
        
        cur.execute(query, params)
        results = cur.fetchall()
        
        cur.close()
        conn.close()
        
        return jsonify({
            'success': True,
            'data': [dict(row) for row in results],
            'count': len(results)
        }), 200
        
    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except psycopg2.Error as e:
        return jsonify({'error': 'Database error occurred'}), 500
    except Exception as e:
        return jsonify({'error': 'An unexpected error occurred'}), 500


@app.route('/api/aggregate', methods=['POST'])
def aggregate_data():
    try:
        data = request.get_json()
        
        table_name = data.get('table')
        aggregations = data.get('aggregations', [])
        group_by = data.get('group_by', [])
        filters = data.get('filters', [])
        
        if not table_name:
            return jsonify({'error': 'Table name is required'}), 400
        
        if not validate_table(table_name):
            return jsonify({'error': 'Invalid or unauthorized table name'}), 400
        
        if not aggregations:
            return jsonify({'error': 'At least one aggregation is required'}), 400
        
        if group_by and not validate_columns(table_name, group_by):
            return jsonify({'error': 'Invalid group by columns'}), 400
        
        select_parts = []
        
        for agg in aggregations:
            func = agg.get('function', '').upper()
            column = agg.get('column')
            alias = agg.get('alias')
            
            if func not in ['COUNT', 'SUM', 'AVG', 'MIN', 'MAX']:
                raise ValueError(f"Invalid aggregation function: {func}")
            
            if column != '*' and not validate_identifier(column, ALLOWED_COLUMNS.get(table_name, set())):
                raise ValueError(f"Invalid column for aggregation: {column}")
            
            if alias and not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', alias):
                raise ValueError(f"Invalid alias: {alias}")
            
            if column == '*':
                agg_expr = sql.SQL("{}(*)").format(sql.SQL(func))
            else:
                agg_expr = sql.SQL("{}({})").format(
                    sql.SQL(func),
                    sql.Identifier(column)
                )
            
            if alias:
                agg_expr = sql.SQL("{} AS {}").format(agg_expr, sql.Identifier(alias))
            
            select_parts.append(agg_expr)
        
        for col in group_by:
            select_parts.append(sql.Identifier(col))
        
        select_clause = sql.SQL("SELECT {}").format(sql.SQL(', ').join(select_parts))
        from_clause = sql.SQL(" FROM {}").format(sql.Identifier(table_name))
        
        where_clause, where_params = build_where_clause(table_name, filters)
        
        if group_by:
            group_clause = sql.SQL(" GROUP BY {}").format(
                sql.SQL(', ').join(map(sql.Identifier, group_by))
            )
        else:
            group_clause = sql.SQL("")
        
        query = select_clause + from_clause + where_clause + group_clause
        
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=extras.RealDictCursor)
        
        cur.execute(query, where_params)
        results = cur.fetchall()
        
        cur.close()
        conn.close()
        
        return jsonify({
            'success': True,
            'data': [dict(row) for row in results],
            'count': len(results)
        }), 200
        
    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except psycopg2.Error as e:
        return jsonify({'error': 'Database error occurred'}), 500
    except Exception as e:
        return jsonify({'error': 'An unexpected error occurred'}), 500


